import{M as e,d as t,h as n,y as r}from"./chunks/runtime-core.esm-bundler.Di_optew.js";var i=JSON.parse(`{"title":"Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"guide/troubleshooting.md","filePath":"guide/troubleshooting.md"}`),a=r({name:`guide/troubleshooting.md`,setup(r){if(typeof window<`u`){let e={"vite-cjs-node-api-deprecated":6}[location.hash.slice(1)];e&&(location.href=`https://v${e}.vite.dev`+location.pathname+location.search+location.hash)}return(r,i)=>(e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /guide\\troubleshooting.md for this page in Markdown format</div><h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to “Troubleshooting”">​</a></h1><p>See <a href="https://rollupjs.org/troubleshooting/" target="_blank" rel="noreferrer">Rollup&#39;s troubleshooting guide</a> for more information too.</p><p>If the suggestions here don&#39;t work, please try posting questions on <a href="https://github.com/vitejs/vite/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a> or in the <code>#help</code> channel of <a href="https://chat.vite.dev" target="_blank" rel="noreferrer">Vite Land Discord</a>.</p><h2 id="cli" tabindex="-1">CLI <a class="header-anchor" href="#cli" aria-label="Permalink to “CLI”">​</a></h2><h3 id="error-cannot-find-module-c-foo-bar-baz-vite-bin-vite-js" tabindex="-1"><code>Error: Cannot find module &#39;C:\\foo\\bar&amp;baz\\vite\\bin\\vite.js&#39;</code> <a class="header-anchor" href="#error-cannot-find-module-c-foo-bar-baz-vite-bin-vite-js" aria-label="Permalink to “Error: Cannot find module &#39;C:\\foo\\bar&amp;baz\\vite\\bin\\vite.js&#39;”">​</a></h3><p>The path to your project folder may include <code>&amp;</code>, which doesn&#39;t work with <code>npm</code> on Windows (<a href="https://github.com/npm/cmd-shim/issues/45" target="_blank" rel="noreferrer">npm/cmd-shim#45</a>).</p><p>You will need to either:</p><ul><li>Switch to another package manager (e.g. <code>pnpm</code>, <code>yarn</code>)</li><li>Remove <code>&amp;</code> from the path to your project</li></ul><h2 id="config" tabindex="-1">Config <a class="header-anchor" href="#config" aria-label="Permalink to “Config”">​</a></h2><h3 id="this-package-is-esm-only" tabindex="-1">This package is ESM only <a class="header-anchor" href="#this-package-is-esm-only" aria-label="Permalink to “This package is ESM only”">​</a></h3><p>When importing an ESM only package by <code>require</code>, the following error happens.</p><blockquote><p>Failed to resolve &quot;foo&quot;. This package is ESM only but it was tried to load by <code>require</code>.</p></blockquote><blockquote><p>Error [ERR_REQUIRE_ESM]: require() of ES Module /path/to/dependency.js from /path/to/vite.config.js not supported. Instead change the require of index.js in /path/to/vite.config.js to a dynamic import() which is available in all CommonJS modules.</p></blockquote><p>In Node.js &lt;=22, ESM files cannot be loaded by <a href="https://nodejs.org/docs/latest-v22.x/api/esm.html#require" target="_blank" rel="noreferrer"><code>require</code></a> by default.</p><p>While it may work using <a href="https://nodejs.org/docs/latest-v22.x/api/modules.html#loading-ecmascript-modules-using-require" target="_blank" rel="noreferrer"><code>--experimental-require-module</code></a>, or Node.js &gt;22, or in other runtimes, we still recommend converting your config to ESM by either:</p><ul><li>adding <code>&quot;type&quot;: &quot;module&quot;</code> to the nearest <code>package.json</code></li><li>renaming <code>vite.config.js</code>/<code>vite.config.ts</code> to <code>vite.config.mjs</code>/<code>vite.config.mts</code></li></ul><h2 id="dev-server" tabindex="-1">Dev Server <a class="header-anchor" href="#dev-server" aria-label="Permalink to “Dev Server”">​</a></h2><h3 id="requests-are-stalled-forever" tabindex="-1">Requests are stalled forever <a class="header-anchor" href="#requests-are-stalled-forever" aria-label="Permalink to “Requests are stalled forever”">​</a></h3><p>If you are using Linux, file descriptor limits and inotify limits may be causing the issue. As Vite does not bundle most of the files, browsers may request many files which require many file descriptors, going over the limit.</p><p>To solve this:</p><ul><li><p>Increase file descriptor limit by <code>ulimit</code></p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Check current limit</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;user-select:none;-webkit-user-select:none;">$ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ulimit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Sn</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Change limit (temporary)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;user-select:none;-webkit-user-select:none;">$ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ulimit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Sn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10000</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # You might need to change the hard limit too</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Restart your browser</span></span></code></pre></div></li><li><p>Increase the following inotify related limits by <code>sysctl</code></p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Check current limits</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;user-select:none;-webkit-user-select:none;">$ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sysctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fs.inotify</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Change limits (temporary)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;user-select:none;-webkit-user-select:none;">$ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sysctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fs.inotify.max_queued_events=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16384</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;user-select:none;-webkit-user-select:none;">$ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sysctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fs.inotify.max_user_instances=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8192</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;user-select:none;-webkit-user-select:none;">$ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sysctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fs.inotify.max_user_watches=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">524288</span></span></code></pre></div></li></ul><p>If the above steps don&#39;t work, you can try adding <code>DefaultLimitNOFILE=65536</code> as an un-commented config to the following files:</p><ul><li>/etc/systemd/system.conf</li><li>/etc/systemd/user.conf</li></ul><p>For Ubuntu Linux, you may need to add the line <code>* - nofile 65536</code> to the file <code>/etc/security/limits.conf</code> instead of updating systemd config files.</p><p>Note that these settings persist but a <strong>restart is required</strong>.</p><p>Alternatively, if the server is running inside a VS Code devcontainer, the request may appear to be stalled. To fix this issue, see <a href="#dev-containers-vs-code-port-forwarding">Dev Containers / VS Code Port Forwarding</a>.</p><h3 id="vite-crashes-with-enospc-error" tabindex="-1">Vite crashes with ENOSPC error <a class="header-anchor" href="#vite-crashes-with-enospc-error" aria-label="Permalink to “Vite crashes with ENOSPC error”">​</a></h3><p>If you see an error like this on Linux:</p><blockquote><p>Error: ENOSPC: System limit for number of file watchers reached</p></blockquote><p>This happens when you have too many files in your project directory (e.g., many images or assets) and exceed the system&#39;s file watcher limit. Linux has a default limit of around 8,192-10,000 file watchers.</p><p>To solve this, you can:</p><ul><li><p>Increase the system file watcher limit:</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Check current limit</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;user-select:none;-webkit-user-select:none;">$ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/sys/fs/inotify/max_user_watches</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Increase limit (temporary)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;user-select:none;-webkit-user-select:none;">$ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sysctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fs.inotify.max_user_watches=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">524288</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Make it permanent - add to /etc/sysctl.conf (or edit if it already exists)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;user-select:none;-webkit-user-select:none;">$ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;fs.inotify.max_user_watches=524288&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tee</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/sysctl.conf</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;user-select:none;-webkit-user-select:none;">$ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sysctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span></span></code></pre></div></li><li><p>Exclude directories with many files from file watching using <a href="/config/server-options#server-watch"><code>server.watch.ignored</code></a></p></li><li><p>Use polling instead of file system events with <a href="/config/server-options#server-watch"><code>server.watch.usePolling</code></a>. Note that polling uses more CPU resources</p></li></ul><h3 id="network-requests-stop-loading" tabindex="-1">Network requests stop loading <a class="header-anchor" href="#network-requests-stop-loading" aria-label="Permalink to “Network requests stop loading”">​</a></h3><p>When using a self-signed SSL certificate, Chrome ignores all caching directives and reloads the content. Vite relies on these caching directives.</p><p>To resolve the problem use a trusted SSL cert.</p><p>See: <a href="https://helpx.adobe.com/mt/experience-manager/kb/cache-problems-on-chrome-with-SSL-certificate-errors.html" target="_blank" rel="noreferrer">Cache problems</a>, <a href="https://bugs.chromium.org/p/chromium/issues/detail?id=110649#c8" target="_blank" rel="noreferrer">Chrome issue</a></p><h4 id="macos" tabindex="-1">macOS <a class="header-anchor" href="#macos" aria-label="Permalink to “macOS”">​</a></h4><p>You can install a trusted cert via the CLI with this command:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>security add-trusted-cert -d -r trustRoot -k ~/Library/Keychains/login.keychain-db your-cert.cer</span></span></code></pre></div><p>Or, by importing it into the Keychain Access app and updating the trust of your cert to &quot;Always Trust.&quot;</p><h3 id="_431-request-header-fields-too-large" tabindex="-1">431 Request Header Fields Too Large <a class="header-anchor" href="#_431-request-header-fields-too-large" aria-label="Permalink to “431 Request Header Fields Too Large”">​</a></h3><p>When the server / WebSocket server receives a large HTTP header, the request will be dropped and the following warning will be shown.</p><blockquote><p>Server responded with status code 431. See <a href="https://vite.dev/guide/troubleshooting.html#_431-request-header-fields-too-large" target="_blank" rel="noreferrer">https://vite.dev/guide/troubleshooting.html#_431-request-header-fields-too-large</a>.</p></blockquote><p>This is because Node.js limits request header size to mitigate <a href="https://www.cve.org/CVERecord?id=CVE-2018-12121" target="_blank" rel="noreferrer">CVE-2018-12121</a>.</p><p>To avoid this, try to reduce your request header size. For example, if the cookie is long, delete it. Or you can use <a href="https://nodejs.org/api/cli.html#--max-http-header-sizesize" target="_blank" rel="noreferrer"><code>--max-http-header-size</code></a> to change max header size.</p><h3 id="dev-containers-vs-code-port-forwarding" tabindex="-1">Dev Containers / VS Code Port Forwarding <a class="header-anchor" href="#dev-containers-vs-code-port-forwarding" aria-label="Permalink to “Dev Containers / VS Code Port Forwarding”">​</a></h3><p>If you are using a Dev Container or port forwarding feature in VS Code, you may need to set the <a href="/config/server-options#server-host"><code>server.host</code></a> option to <code>127.0.0.1</code> in the config to make it work.</p><p>This is because <a href="https://github.com/microsoft/vscode-remote-release/issues/7029" target="_blank" rel="noreferrer">the port forwarding feature in VS Code does not support IPv6</a>.</p><p>See <a href="https://github.com/vitejs/vite/issues/16522" target="_blank" rel="noreferrer">#16522</a> for more details.</p><h2 id="hmr" tabindex="-1">HMR <a class="header-anchor" href="#hmr" aria-label="Permalink to “HMR”">​</a></h2><h3 id="vite-detects-a-file-change-but-the-hmr-is-not-working" tabindex="-1">Vite detects a file change but the HMR is not working <a class="header-anchor" href="#vite-detects-a-file-change-but-the-hmr-is-not-working" aria-label="Permalink to “Vite detects a file change but the HMR is not working”">​</a></h3><p>You may be importing a file with a different case. For example, <code>src/foo.js</code> exists and <code>src/bar.js</code> contains:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;./Foo.js&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> // should be &#39;./foo.js&#39;</span></span></code></pre></div><p>Related issue: <a href="https://github.com/vitejs/vite/issues/964" target="_blank" rel="noreferrer">#964</a></p><h3 id="vite-does-not-detect-a-file-change" tabindex="-1">Vite does not detect a file change <a class="header-anchor" href="#vite-does-not-detect-a-file-change" aria-label="Permalink to “Vite does not detect a file change”">​</a></h3><p>If you are running Vite with WSL2, Vite cannot watch file changes in some conditions. See <a href="/config/server-options#server-watch"><code>server.watch</code> option</a>.</p><h3 id="a-full-reload-happens-instead-of-hmr" tabindex="-1">A full reload happens instead of HMR <a class="header-anchor" href="#a-full-reload-happens-instead-of-hmr" aria-label="Permalink to “A full reload happens instead of HMR”">​</a></h3><p>If HMR is not handled by Vite or a plugin, a full reload will happen as it&#39;s the only way to refresh the state.</p><p>If HMR is handled but it is within a circular dependency, a full reload will also happen to recover the execution order. To solve this, try breaking the loop. You can run <code>vite --debug hmr</code> to log the circular dependency path if a file change triggered it.</p><h2 id="build" tabindex="-1">Build <a class="header-anchor" href="#build" aria-label="Permalink to “Build”">​</a></h2><h3 id="built-file-does-not-work-because-of-cors-error" tabindex="-1">Built file does not work because of CORS error <a class="header-anchor" href="#built-file-does-not-work-because-of-cors-error" aria-label="Permalink to “Built file does not work because of CORS error”">​</a></h3><p>If the HTML file output was opened with <code>file</code> protocol, the scripts won&#39;t run with the following error.</p><blockquote><p>Access to script at &#39;file:///foo/bar.js&#39; from origin &#39;null&#39; has been blocked by CORS policy: Cross origin requests are only supported for protocol schemes: http, data, isolated-app, chrome-extension, chrome, https, chrome-untrusted.</p></blockquote><blockquote><p>Cross-Origin Request Blocked: The Same Origin Policy disallows reading the remote resource at file:///foo/bar.js. (Reason: CORS request not http).</p></blockquote><p>See <a href="https://developer.mozilla.org/en-US/docs/Web/HTTP/CORS/Errors/CORSRequestNotHttp" target="_blank" rel="noreferrer">Reason: CORS request not HTTP - HTTP | MDN</a> for more information about why this happens.</p><p>You will need to access the file with <code>http</code> protocol. The easiest way to achieve this is to run <code>npx vite preview</code>.</p><h3 id="no-such-file-or-directory-error-due-to-case-sensitivity" tabindex="-1">No such file or directory error due to case sensitivity <a class="header-anchor" href="#no-such-file-or-directory-error-due-to-case-sensitivity" aria-label="Permalink to “No such file or directory error due to case sensitivity”">​</a></h3><p>If you encounter errors like <code>ENOENT: no such file or directory</code> or <code>Module not found</code>, this often occurs when your project was developed on a case-insensitive filesystem (Windows / macOS) but built on a case-sensitive one (Linux). Please make sure that the imports have the correct casing.</p><h3 id="failed-to-fetch-dynamically-imported-module-error" tabindex="-1"><code>Failed to fetch dynamically imported module</code> error <a class="header-anchor" href="#failed-to-fetch-dynamically-imported-module-error" aria-label="Permalink to “Failed to fetch dynamically imported module error”">​</a></h3><blockquote><p>TypeError: Failed to fetch dynamically imported module</p></blockquote><p>This error occurs in several cases:</p><ul><li>Version skew</li><li>Poor network conditions</li><li>Browser extensions blocking requests</li></ul><h4 id="version-skew" tabindex="-1">Version skew <a class="header-anchor" href="#version-skew" aria-label="Permalink to “Version skew”">​</a></h4><p>When you deploy a new version of your application, the HTML file and the JS files still reference old chunk names that were deleted in the new deployment. This happens when:</p><ol><li>Users have an old version of your app cached in their browser</li><li>You deploy a new version with different chunk names (due to code changes)</li><li>The cached HTML tries to load chunks that no longer exist</li></ol><p>If you are using a framework, refer to their documentation first as it may have a built-in solution for this problem.</p><p>To resolve this, you can:</p><ul><li><strong>Keep old chunks temporarily</strong>: Consider keeping the previous deployment&#39;s chunks for a period to allow cached users to transition smoothly.</li><li><strong>Use a service worker</strong>: Implement a service worker that will prefetch all the assets and cache them.</li><li><strong>Prefetch the dynamic chunks</strong>: Note that this does not help if your HTML file is cached by the browser due to <code>Cache-Control</code> headers.</li><li><strong>Implement a graceful fallback</strong>: Implement error handling for dynamic imports to reload the page when chunks are missing. See <a href="./build#load-error-handling">Load Error Handling</a> for more details.</li></ul><h4 id="poor-network-conditions" tabindex="-1">Poor network conditions <a class="header-anchor" href="#poor-network-conditions" aria-label="Permalink to “Poor network conditions”">​</a></h4><p>This error may occur in unstable network environments. For example, when the request fails due to network errors or server downtime.</p><p>Note that you cannot retry the dynamic import due to browser limitations (<a href="https://github.com/whatwg/html/issues/6768" target="_blank" rel="noreferrer">whatwg/html#6768</a>).</p><h4 id="browser-extensions-blocking-requests" tabindex="-1">Browser extensions blocking requests <a class="header-anchor" href="#browser-extensions-blocking-requests" aria-label="Permalink to “Browser extensions blocking requests”">​</a></h4><p>The error may also occur if the browser extensions (like ad-blockers) are blocking that request.</p><p>It might be possible to work around by selecting a different chunk name by <a href="./../config/build-options#build-rolldownoptions"><code>build.rolldownOptions.output.chunkFileNames</code></a>, as these extensions often block requests based on file names (e.g. names containing <code>ad</code>, <code>track</code>).</p><h2 id="optimized-dependencies" tabindex="-1">Optimized Dependencies <a class="header-anchor" href="#optimized-dependencies" aria-label="Permalink to “Optimized Dependencies”">​</a></h2><h3 id="outdated-pre-bundled-deps-when-linking-to-a-local-package" tabindex="-1">Outdated pre-bundled deps when linking to a local package <a class="header-anchor" href="#outdated-pre-bundled-deps-when-linking-to-a-local-package" aria-label="Permalink to “Outdated pre-bundled deps when linking to a local package”">​</a></h3><p>The hash key used to invalidate optimized dependencies depends on the package lock contents, the patches applied to dependencies, and the options in the Vite config file that affects the bundling of node modules. This means that Vite will detect when a dependency is overridden using a feature as <a href="https://docs.npmjs.com/cli/v9/configuring-npm/package-json#overrides" target="_blank" rel="noreferrer">npm overrides</a>, and re-bundle your dependencies on the next server start. Vite won&#39;t invalidate the dependencies when you use a feature like <a href="https://docs.npmjs.com/cli/v9/commands/npm-link" target="_blank" rel="noreferrer">npm link</a>. In case you link or unlink a dependency, you&#39;ll need to force re-optimization on the next server start by using <code>vite --force</code>. We recommend using overrides instead, which are supported now by every package manager (see also <a href="https://pnpm.io/9.x/package_json#pnpmoverrides" target="_blank" rel="noreferrer">pnpm overrides</a> and <a href="https://yarnpkg.com/configuration/manifest/#resolutions" target="_blank" rel="noreferrer">yarn resolutions</a>).</p><h2 id="performance-bottlenecks" tabindex="-1">Performance Bottlenecks <a class="header-anchor" href="#performance-bottlenecks" aria-label="Permalink to “Performance Bottlenecks”">​</a></h2><p>If you suffer any application performance bottlenecks resulting in slow load times, you can start the built-in Node.js inspector with your Vite dev server or when building your application to create the CPU profile:</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-378" id="tab-379" checked><label data-title="dev server" for="tab-379">dev server</label><input type="radio" name="group-378" id="tab-380"><label data-title="build" for="tab-380">build</label></div><div class="blocks"><div class="language-bash active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vite</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --profile</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --open</span></span></code></pre></div><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vite</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --profile</span></span></code></pre></div></div></div><div class="tip custom-block"><p class="custom-block-title">Vite Dev Server</p><p>Once your application is opened in the browser, just await finish loading it and then go back to the terminal and press <code>p</code> key (will stop the Node.js inspector) then press <code>q</code> key to stop the dev server.</p></div><p>Node.js inspector will generate <code>vite-profile-0.cpuprofile</code> in the root folder, go to <a href="https://www.speedscope.app/" target="_blank" rel="noreferrer">https://www.speedscope.app/</a>, and upload the CPU profile using the <code>BROWSE</code> button to inspect the result.</p><p>You can install <a href="https://github.com/antfu/vite-plugin-inspect" target="_blank" rel="noreferrer">vite-plugin-inspect</a>, which lets you inspect the intermediate state of Vite plugins and can also help you to identify which plugins or middlewares are the bottleneck in your applications. The plugin can be used in both dev and build modes. Check the readme file for more details.</p><h2 id="others" tabindex="-1">Others <a class="header-anchor" href="#others" aria-label="Permalink to “Others”">​</a></h2><h3 id="module-externalized-for-browser-compatibility" tabindex="-1">Module externalized for browser compatibility <a class="header-anchor" href="#module-externalized-for-browser-compatibility" aria-label="Permalink to “Module externalized for browser compatibility”">​</a></h3><p>When you use a Node.js module in the browser, Vite will output the following warning.</p><blockquote><p>Module &quot;fs&quot; has been externalized for browser compatibility. Cannot access &quot;fs.readFile&quot; in client code.</p></blockquote><p>This is because Vite does not automatically polyfill Node.js modules.</p><p>We recommend avoiding Node.js modules for browser code to reduce the bundle size, although you can add polyfills manually. If the module is imported from a third-party library (that&#39;s meant to be used in the browser), it&#39;s advised to report the issue to the respective library.</p><h3 id="syntax-error-type-error-happens" tabindex="-1">Syntax Error / Type Error happens <a class="header-anchor" href="#syntax-error-type-error-happens" aria-label="Permalink to “Syntax Error / Type Error happens”">​</a></h3><p>Vite cannot handle and does not support code that only runs on non-strict mode (sloppy mode). This is because Vite uses ESM and it is always <a href="https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Strict_mode" target="_blank" rel="noreferrer">strict mode</a> inside ESM.</p><p>For example, you might see these errors.</p><blockquote><p>[ERROR] With statements cannot be used with the &quot;esm&quot; output format due to strict mode</p></blockquote><blockquote><p>TypeError: Cannot create property &#39;foo&#39; on boolean &#39;false&#39;</p></blockquote><p>If these codes are used inside dependencies, you could use <a href="https://github.com/ds300/patch-package" target="_blank" rel="noreferrer"><code>patch-package</code></a> (or <a href="https://yarnpkg.com/cli/patch" target="_blank" rel="noreferrer"><code>yarn patch</code></a> or <a href="https://pnpm.io/cli/patch" target="_blank" rel="noreferrer"><code>pnpm patch</code></a>) for an escape hatch.</p><h3 id="browser-extensions" tabindex="-1">Browser extensions <a class="header-anchor" href="#browser-extensions" aria-label="Permalink to “Browser extensions”">​</a></h3><p>Some browser extensions (like ad-blockers) may prevent the Vite client from sending requests to the Vite dev server. You may see a white screen without logged errors in this case. You may also see the following error:</p><blockquote><p>TypeError: Failed to fetch dynamically imported module</p></blockquote><p>Try disabling extensions if you have this issue.</p><h3 id="cross-drive-links-on-windows" tabindex="-1">Cross drive links on Windows <a class="header-anchor" href="#cross-drive-links-on-windows" aria-label="Permalink to “Cross drive links on Windows”">​</a></h3><p>If there&#39;s a cross drive links in your project on Windows, Vite may not work.</p><p>An example of cross drive links are:</p><ul><li>a virtual drive linked to a folder by <code>subst</code> command</li><li>a symlink/junction to a different drive by <code>mklink</code> command (e.g. Yarn global cache)</li></ul><p>Related issue: <a href="https://github.com/vitejs/vite/issues/10802" target="_blank" rel="noreferrer">#10802</a></p><h3 id="default-import-unexpectedly-returns-an-object" tabindex="-1">Default import unexpectedly returns an object <a class="header-anchor" href="#default-import-unexpectedly-returns-an-object" aria-label="Permalink to “Default import unexpectedly returns an object”">​</a></h3><p>The default import returns the <code>module.exports</code> object for CJS modules, while you may expect it to return the <code>module.exports.default</code> value.</p><p>This may cause errors like:</p><blockquote><p>Element type is invalid: expected a string (for built-in components) or a class/function (for composite components) but got: object.</p></blockquote><blockquote><p>foo is not a function</p></blockquote><p>See Rolldown&#39;s docs about this problem for more details: <a href="https://rolldown.rs/in-depth/bundling-cjs#ambiguous-default-import-from-cjs-modules" target="_blank" rel="noreferrer">Ambiguous <code>default</code> import from CJS modules - Bundling CJS | Rolldown</a>.</p>`,121)]]))}});export{i as __pageData,a as default};